def extended_gcd(a, b):
    if b == 0:
        return (a, 1, 0)
    else:
        gcd, x1, y1 = extended_gcd(b, a % b)
        x = y1
        y = x1 - (a // b) * y1
        return (gcd, x, y)

# Example: gcd(12, 5)
gcd, x, y = extended_gcd(12, 5)
print(f"GCD: {gcd}, x: {x}, y: {y}")
# Output: GCD: 1, x: -2, y: 5
# Verification: 12*(-2) + 5*(5) = -24 + 25 = 1

FUNCTION DivisionAlgorithm(a, b)
    // Assumes b > 0
    q = 0
    r = a

    // If a is negative, handle separately
    IF a >= 0 THEN
        q = a // b  (integer division)
        r = a MOD b
    ELSE
        // For negative a, find correct q and r
        q = -((-a + b - 1) // b)
        r = a - q * b
    END IF

    // Verify: a = b*q + r and 0 <= r < b
    RETURN (q, r)
END FUNCTION

// Example: a = 67, b = 12
// q = 5, r = 7 (since 67 = 12*5 + 7, 0 <= 7 < 12)
